func parseConfig(json gjson.Result, c *PluginConfig, log wrapper.Log) error {
	c.RedisInfo.ServiceName = json.Get("redis.serviceName").String()
	if c.RedisInfo.ServiceName == "" {
		return errors.New("redis service name must not by empty")
	}
	c.RedisInfo.ServicePort = int(json.Get("redis.servicePort").Int())
	if c.RedisInfo.ServicePort == 0 {
		if strings.HasSuffix(c.RedisInfo.ServiceName, ".static") {
			// use default logic port which is 80 for static service
			c.RedisInfo.ServicePort = 80
		} else {
			c.RedisInfo.ServicePort = 6379
		}
	}
	c.RedisInfo.Username = json.Get("redis.username").String()
	c.RedisInfo.Password = json.Get("redis.password").String()
	c.RedisInfo.IndexName = json.Get("redis.indexName").String()
	c.RedisInfo.Timeout = int(json.Get("redis.timeout").Int())
	if c.RedisInfo.Timeout == 0 {
		c.RedisInfo.Timeout = 1000
	}
	c.CacheKeyFrom.RequestBody = json.Get("cacheKeyFrom.requestBody").String()
	if c.CacheKeyFrom.RequestBody == "" {
		c.CacheKeyFrom.RequestBody = "messages.@reverse.0.content"
	}
	c.CacheValueFrom.ResponseBody = json.Get("cacheValueFrom.responseBody").String()
	if c.CacheValueFrom.ResponseBody == "" {
		c.CacheValueFrom.ResponseBody = "choices.0.message.content"
	}
	c.CacheStreamValueFrom.ResponseBody = json.Get("cacheStreamValueFrom.responseBody").String()
	if c.CacheStreamValueFrom.ResponseBody == "" {
		c.CacheStreamValueFrom.ResponseBody = "choices.0.delta.content"
	}
	c.ReturnResponseTemplate = json.Get("returnResponseTemplate").String()
	if c.ReturnResponseTemplate == "" {
		c.ReturnResponseTemplate = `{"id":"from-cache","choices":[{"index":0,"message":{"role":"assistant","content":"%s"},"finish_reason":"stop"}],"model":"gpt-4o","object":"chat.completion","usage":{"prompt_tokens":0,"completion_tokens":0,"total_tokens":0}}`
	}
	c.ReturnStreamResponseTemplate = json.Get("returnStreamResponseTemplate").String()
	if c.ReturnStreamResponseTemplate == "" {
		c.ReturnStreamResponseTemplate = `data:{"id":"from-cache","choices":[{"index":0,"delta":{"role":"assistant","content":"%s"},"finish_reason":"stop"}],"model":"gpt-4o","object":"chat.completion","usage":{"prompt_tokens":0,"completion_tokens":0,"total_tokens":0}}` + "\n\ndata:[DONE]\n\n"
	}
	c.CacheKeyPrefix = json.Get("cacheKeyPrefix").String()
	if c.CacheKeyPrefix == "" {
		c.CacheKeyPrefix = DefaultCacheKeyPrefix
	}
	c.redisClient = wrapper.NewRedisClusterClient(wrapper.FQDNCluster{
		FQDN: c.RedisInfo.ServiceName,
		Port: int64(c.RedisInfo.ServicePort),
	})

	c.DashScopeInfo.APIKey = json.Get("dashscope.apiKey").String()
	c.DashScopeInfo.ServiceName = json.Get("dashscope.serviceName").String()
	c.DashScopeInfo.ServicePort = json.Get("dashscope.servicePort").Int()
	c.DashScopeInfo.Domin = json.Get("dashscope.domain").String()

	c.DashScopeClient = wrapper.NewClusterClient(wrapper.DnsCluster{
		ServiceName: c.DashScopeInfo.ServiceName,
		Port:        c.DashScopeInfo.ServicePort,
		Domain:      c.DashScopeInfo.Domin,
	})

	return c.redisClient.Init(c.RedisInfo.Username, c.RedisInfo.Password, int64(c.RedisInfo.Timeout))
}

func onHttpRequestHeaders(ctx wrapper.HttpContext, config PluginConfig, log wrapper.Log) types.Action {
	log.Info("onHttpRequestHeaders start")
	defer log.Info("onHttpRequestHeaders end")
	contentType, _ := proxywasm.GetHttpRequestHeader("content-type")
	// The request does not have a body.
	if contentType == "" {
		return types.ActionContinue
	}
	if !strings.Contains(contentType, "application/json") {
		log.Warnf("content is not json, can't process:%s", contentType)
		ctx.DontReadRequestBody()
		return types.ActionContinue
	}
	proxywasm.RemoveHttpRequestHeader("Accept-Encoding")
	// The request has a body and requires delaying the header transmission until a cache miss occurs,
	// at which point the header should be sent.
	return types.HeaderStopIteration
}

func TrimQuote(source string) string {
	return strings.Trim(source, `"`)
}

func FloatSliceToString(slice []float32) string {
	strs := make([]string, len(slice))
	for i, v := range slice {
		strs[i] = strconv.FormatFloat(float64(v), 'f', -1, 32)
	}
	return "[" + strings.Join(strs, ",") + "]"
}

func SearchVector(ctx wrapper.HttpContext, config PluginConfig, key string, rawRequest Request, stream bool, log wrapper.Log) {
	log.Info("[onHttpRequestBody] 开始转向量了")
	// text to vector
	requestEmbedding := dashscope.Request{
		Model: "text-embedding-v2",
		Input: dashscope.Input{
			Texts: []string{key},
		},
		Parameter: dashscope.Parameter{
			TextType: "query",
		},
	}

	headers := [][2]string{{"Content-Type", "application/json"}, {"Authorization", "Bearer " + config.DashScopeInfo.APIKey}}
	reqEmbeddingSerialized, _ := json.Marshal(requestEmbedding)
	err := config.DashScopeClient.Post(
		"/api/v1/services/embeddings/text-embedding/text-embedding",
		headers,
		reqEmbeddingSerialized,
		func(statusCode int, responseHeaders http.Header, responseBody []byte) {
			//vector search
			var responseEmbedding dashscope.Response
			_ = json.Unmarshal(responseBody, &responseEmbedding)
			vector := responseEmbedding.Output.Embeddings[0].Embedding
			sVector := FloatSliceToString(vector)

			log.Infof("[onHttpRequestBody] svector: ", sVector)

			err := config.redisClient.TvsKnnSearch(config.RedisInfo.IndexName, 1, sVector, tair.TvsKnnSearchArgs{}.New().MaxDist(0.25), func(response resp.Value) {
				if err := response.Error(); err != nil {
					log.Errorf("[onHttpRequestBody] tair search vector:%s failed, err:%v", key, err)
					proxywasm.ResumeHttpRequest()
					return
				}

				log.Infof("[onHttpRequestBody] TvsKnnSearch: %s", response.String())

				if response.String() == "[]" { // cache miss
					log.Infof("[onHttpRequestBody] cache miss not find key:%s", key)
					//add system role message
					var systemMessage Message
					systemMessage.Role = "system"
					systemMessage.Content = promptTemplate.Instruction + promptTemplate.OutputFormat + promptTemplate.Order + promptTemplate.Example

					//从redis中获取上一个问题
					config.redisClient.Get("lastquestion", func(response resp.Value) {
						if err := response.Error(); err != nil {
							log.Errorf("[onHttpRequestBody] redis get key:%s failed, err:%v", "lastquestion", err)
						}
						if response.IsNull() {
							log.Infof("[onHttpRequestBody] cache miss, key:%s", "lastquestion")

							newMessages := []Message{systemMessage}
							newMessages = append(newMessages, rawRequest.Messages...)
							rawRequest.Messages = newMessages

							//replace old message and resume request qwen
							newbody, err := json.Marshal(rawRequest)
							if err != nil {
								proxywasm.ResumeHttpRequest()
								return
							} else {
								log.Infof("[onHttpRequestBody] newRequestBody: ", string(newbody))
								err := proxywasm.ReplaceHttpRequestBody(newbody)
								if err != nil {
									log.Info("替换失败")
									proxywasm.SendHttpResponse(200, [][2]string{{"content-type", "application/json; charset=utf-8"}}, []byte(fmt.Sprintf(config.ReturnResponseTemplate, "替换失败"+err.Error())), -1)
								}
								log.Info("[onHttpRequestBody] request替换成功")
								proxywasm.ResumeHttpRequest()
							}
						}

						log.Debugf("[onHttpRequestBody] cache hit, key:%s", "lastquestion")
						lastquestion := response.String()
						config.redisClient.Get("lastanswer", func(response resp.Value) {
							if err := response.Error(); err != nil {
								log.Errorf("[onHttpRequestBody] redis get key:%s failed, err:%v", "lastanswer", err)
							}

							if response.IsNull() {
								log.Infof("[onHttpRequestBody] cache miss, key:%s", "lastanswer")
							}

							log.Debugf("[onHttpRequestBody] cache hit, key:%s", "lastanswer")

							historyPromptTemplate := "history: human:%s AI:%s question:%s"

							prompt := fmt.Sprintf(historyPromptTemplate, lastquestion, response.String(), key)
							rawRequest.Messages[len(rawRequest.Messages)-1].Content = prompt

							newMessages := []Message{systemMessage}
							newMessages = append(newMessages, rawRequest.Messages...)
							rawRequest.Messages = newMessages

							//replace old message and resume request qwen
							newbody, err := json.Marshal(rawRequest)
							if err != nil {
								proxywasm.ResumeHttpRequest()
								return
							} else {
								log.Infof("[onHttpRequestBody] newRequestBody: ", string(newbody))
								err := proxywasm.ReplaceHttpRequestBody(newbody)
								if err != nil {
									log.Info("替换失败")
									proxywasm.SendHttpResponse(200, [][2]string{{"content-type", "application/json; charset=utf-8"}}, []byte(fmt.Sprintf(config.ReturnResponseTemplate, "替换失败"+err.Error())), -1)
								}
								log.Info("[onHttpRequestBody] request替换成功")
								proxywasm.ResumeHttpRequest()
							}
						})
					})
				} else {
					//cache hit
					knnresp := response.Array()
					firstKey := knnresp[0]

					log.Infof("[onHttpRequestBody] cache hit, key:%s", firstKey.String())
					config.redisClient.TvsHGetAll(config.RedisInfo.IndexName, firstKey.String(), func(response resp.Value) {
						ctx.SetContext(CacheKeyContextKey, nil)
						log.Infof("[onHttpRequestBody] TvsHGetAll: %s", response.String())
						getallresp := response.Array()
						answerk := -1
						for k, v := range getallresp {
							if v.String() == "answer" {
								answerk = k
								break
							}
						}

						log.Infof("[onHttpRequestBody] answerk: %d, getallresp[answerk+1]:= %s", answerk, getallresp[answerk+1])

						if !stream {
							proxywasm.SendHttpResponse(200, [][2]string{{"content-type", "application/json; charset=utf-8"}}, []byte(fmt.Sprintf(config.ReturnResponseTemplate, getallresp[answerk+1])), -1)
						} else {
							proxywasm.SendHttpResponse(200, [][2]string{{"content-type", "text/event-stream; charset=utf-8"}}, []byte(fmt.Sprintf(config.ReturnStreamResponseTemplate, getallresp[answerk+1])), -1)
						}
					})
				}
			})
			if err != nil {
				log.Error("[onHttpRequestBody] key search failed")
				proxywasm.ResumeHttpRequest()
				return
			}
			//	proxywasm.ResumeHttpRequest()
		}, 50000)
	if err != nil {
		log.Infof("[onHttpRequestBody] 向量转错了：", err.Error())
	}
}

func onHttpRequestBody(ctx wrapper.HttpContext, config PluginConfig, body []byte, log wrapper.Log) types.Action {
	log.Info("onHttpRequestBody start")
	defer log.Info("onHttpRequestBody end")

	log.Infof("[onHttpRequestBody] body to string: ", string(body))

	var rawRequest Request
	err := json.Unmarshal(body, &rawRequest)
	if err != nil {
		log.Infof("[onHttpRequestBody] body json umarshal err: ", err.Error())
		return types.ActionContinue
	}

	stream := false

	if rawRequest.Stream {
		stream = true
		ctx.SetContext(StreamContextKey, struct{}{})
	} else if ctx.GetContext(StreamContextKey) != nil {

		stream = true
	}

	var key string
	messageLength := len(rawRequest.Messages)
	log.Infof("[onHttpRequestBody] messageLength: ", messageLength)
	if messageLength > 0 {
		key = rawRequest.Messages[messageLength-1].Content
		log.Infof("[onHttpRequestBody] key: ", key)
	} else {
		return types.ActionContinue
	}

	if key == "" {
		log.Debug("parse key from request body failed")
		return types.ActionContinue
	}
	log.Infof("CacheKeyContextKey: ", CacheKeyContextKey)
	ctx.SetContext(CacheKeyContextKey, key)
	log.Infof("[onHttpRequestBody] IndexName: ", config.RedisInfo.IndexName)
	//get tairvector index

	err = config.redisClient.TvsGetIndex(config.RedisInfo.IndexName, func(response resp.Value) {
		log.Infof("[onHttpRequestBody] TvsGetIndex: ", response.String())
		if err := response.Error(); err != nil {
			log.Errorf("tair get index:%s failed, err:%v", key, err)
			proxywasm.ResumeHttpRequest()
		}

		if response.String() == "[]" { //not find index
			log.Infof("[onHttpRequestBody] not find index:%s", config.RedisInfo.IndexName)
			//create index
			config.redisClient.TvsCreateIndex(config.RedisInfo.IndexName, 1536, "HNSW", "COSINE", nil, func(response resp.Value) {
				SearchVector(ctx, config, key, rawRequest, stream, log)
			})
		} else { //find index
			log.Infof("[onHttpRequestBody] find index:%s", config.RedisInfo.IndexName)
			SearchVector(ctx, config, key, rawRequest, stream, log)
		}
	})

	if err != nil {
		log.Error("get index failed")
		return types.ActionContinue
	}

	return types.ActionPause
}

